 1→/**
 2→ * Types for starred message history
 3→ */
 4→
 5→export interface StarredMessage {
 6→  /** Unique ID of the starred turn */
 7→  turnId: string;
 8→  /** Content preview of the message */
 9→  content: string;
10→  /** Conversation ID (computed hash) */
11→  conversationId: string;
12→  /** Conversation URL */
13→  conversationUrl: string;
14→  /** Conversation title (optional) */
15→  conversationTitle?: string;
16→  /** Timestamp when the message was starred */
17→  starredAt: number;
18→}
