  1→/**
  2→ * Service for managing starred messages across all conversations
  3→ * Uses message passing to background script to prevent race conditions
  4→ */
  5→import { eventBus } from './EventBus';
  6→import type { StarredMessage, StarredMessagesData } from './starredTypes';
  7→
  8→export class StarredMessagesService {
  9→  /**
 10→   * Send message to background script and wait for response
 11→   */
 12→  private static async sendMessage<T>(type: string, payload?: unknown): Promise<T> {
 13→    return new Promise((resolve, reject) => {
 14→      chrome.runtime.sendMessage({ type, payload }, (response) => {
 15→        if (chrome.runtime.lastError) {
 16→          reject(new Error(chrome.runtime.lastError.message));
 17→          return;
 18→        }
 19→        if (!response || !response.ok) {
 20→          reject(new Error(response?.error || 'Operation failed'));
 21→          return;
 22→        }
 23→        resolve(response as T);
 24→      });
 25→    });
 26→  }
 27→
 28→  /**
 29→   * Get all starred messages from storage
 30→   */
 31→  static async getAllStarredMessages(): Promise<StarredMessagesData> {
 32→    try {
 33→      const response = await this.sendMessage<{ ok: boolean; data: StarredMessagesData }>(
 34→        'gv.starred.getAll',
 35→      );
 36→      return response.data || { messages: {} };
 37→    } catch (error) {
 38→      console.error('[StarredMessagesService] Failed to get starred messages:', error);
 39→      return { messages: {} };
 40→    }
 41→  }
 42→
 43→  /**
 44→   * Get starred messages for a specific conversation
 45→   */
 46→  static async getStarredMessagesForConversation(
 47→    conversationId: string,
 48→  ): Promise<StarredMessage[]> {
 49→    try {
 50→      const response = await this.sendMessage<{ ok: boolean; messages: StarredMessage[] }>(
 51→        'gv.starred.getForConversation',
 52→        { conversationId },
 53→      );
 54→      return response.messages || [];
 55→    } catch (error) {
 56→      console.error('[StarredMessagesService] Failed to get starred messages:', error);
 57→      return [];
 58→    }
 59→  }
 60→
 61→  /**
 62→   * Add a starred message - delegated to background script
 63→   */
 64→  static async addStarredMessage(message: StarredMessage): Promise<void> {
 65→    try {
 66→      const response = await this.sendMessage<{ ok: boolean; added: boolean }>(
 67→        'gv.starred.add',
 68→        message,
 69→      );
 70→
 71→      if (response.added) {
 72→        // Emit event for cross-component synchronization
 73→        eventBus.emit('starred:added', {
 74→          conversationId: message.conversationId,
 75→          turnId: message.turnId,
 76→        });
 77→
 78→        // Also update localStorage for backward compatibility
 79→        this.updateLegacyStorage(message.conversationId, message.turnId, 'add');
 80→      }
 81→    } catch (error) {
 82→      console.error('[StarredMessagesService] Failed to add starred message:', error);
 83→    }
 84→  }
 85→
 86→  /**
 87→   * Remove a starred message - delegated to background script
 88→   */
 89→  static async removeStarredMessage(conversationId: string, turnId: string): Promise<void> {
 90→    try {
 91→      const response = await this.sendMessage<{ ok: boolean; removed: boolean }>(
 92→        'gv.starred.remove',
 93→        { conversationId, turnId },
 94→      );
 95→
 96→      if (response.removed) {
 97→        // Emit event for cross-component synchronization
 98→        eventBus.emit('starred:removed', {
 99→          conversationId,
100→          turnId,
101→        });
102→
103→        // Also update localStorage for backward compatibility
104→        this.updateLegacyStorage(conversationId, turnId, 'remove');
105→      }
106→    } catch (error) {
107→      console.error('[StarredMessagesService] Failed to remove starred message:', error);
108→    }
109→  }
110→
111→  /**
112→   * Update legacy localStorage format for backward compatibility
113→   * This ensures TimelineManager's storage event listener works
114→   */
115→  private static updateLegacyStorage(
116→    conversationId: string,
117→    turnId: string,
118→    action: 'add' | 'remove',
119→  ): void {
120→    try {
121→      const key = `geminiTimelineStars:${conversationId}`;
122→      const raw = localStorage.getItem(key);
123→      let ids: string[] = [];
124→
125→      if (raw) {
126→        try {
127→          ids = JSON.parse(raw);
128→          if (!Array.isArray(ids)) ids = [];
129→        } catch {
130→          ids = [];
131→        }
132→      }
133→
134→      if (action === 'add') {
135→        if (!ids.includes(turnId)) {
136→          ids.push(turnId);
137→        }
138→      } else {
139→        ids = ids.filter((id) => id !== turnId);
140→      }
141→
142→      localStorage.setItem(key, JSON.stringify(ids));
143→    } catch (error) {
144→      console.debug('[StarredMessagesService] Failed to update legacy storage:', error);
145→    }
146→  }
147→
148→  /**
149→   * Check if a message is starred
150→   */
151→  static async isMessageStarred(conversationId: string, turnId: string): Promise<boolean> {
152→    const messages = await this.getStarredMessagesForConversation(conversationId);
153→    return messages.some((m) => m.turnId === turnId);
154→  }
155→
156→  /**
157→   * Get all starred messages sorted by timestamp (newest first)
158→   */
159→  static async getAllStarredMessagesSorted(): Promise<StarredMessage[]> {
160→    const data = await this.getAllStarredMessages();
161→    const allMessages: StarredMessage[] = [];
162→
163→    Object.values(data.messages).forEach((messages) => {
164→      allMessages.push(...messages);
165→    });
166→
167→    return allMessages.sort((a, b) => b.starredAt - a.starredAt);
168→  }
169→}
