 34→  const handleMessageClick = async (message: StarredMessage) => {
 35→    // Check if we're already on a Gemini page
 36→    const [currentTab] = await chrome.tabs.query({ active: true, currentWindow: true });
 37→    const targetUrl = `${message.conversationUrl}#gv-turn-${message.turnId}`;
 38→
 39→    const isGeminiPage =
 40→      currentTab?.url?.includes('gemini.google.com') ||
 41→      currentTab?.url?.includes('aistudio.google.com');
 42→
 43→    if (isGeminiPage && currentTab?.id) {
 44→      // Navigate in the same tab (SPA navigation)
 45→      await chrome.tabs.update(currentTab.id, { url: targetUrl });
 46→      // Close the popup
