 66→  const formatDate = (timestamp: number): string => {
 67→    const date = new Date(timestamp);
 68→    const now = new Date();
 69→    const diffMs = now.getTime() - date.getTime();
 70→    const diffHours = Math.floor(diffMs / (1000 * 60 * 60));
 71→    const diffDays = Math.floor(diffMs / (1000 * 60 * 60 * 24));
 72→
 73→    // Within 24 hours: show hours
 74→    if (diffHours < 24) {
 75→      if (diffHours === 0) {
 76→        return t('justNow');
 77→      }
 78→      return `${diffHours} ${t('hoursAgo')}`;
 79→    } else if (diffDays === 1) {
 80→      return t('yesterday');
 81→    } else if (diffDays < 7) {
 82→      return `${diffDays} ${t('daysAgo')}`;
 83→    } else {
 84→      return date.toLocaleDateString();
 85→    }
 86→  };
 87→
 88→  const truncateText = (text: string, maxLength: number): string => {
 89→    if (text.length <= maxLength) return text;
 90→    return text.slice(0, maxLength) + '...';
 91→  };
 92→
 93→  return (
 94→    <div className="bg-background text-foreground flex h-[600px] w-[360px] flex-col">
 95→      {/* Header */}
 96→      <div className="from-primary/10 via-accent/5 border-border/50 border-b bg-linear-to-br to-transparent px-5 py-4 backdrop-blur-sm">
 97→        <div className="mb-2 flex items-center justify-between">
 98→          <h1 className="from-primary to-primary/70 bg-linear-to-r bg-clip-text text-xl font-bold text-transparent">
 99→            {t('starredHistory')}
100→          </h1>
101→          <Button
102→            onClick={onClose}
103→            variant="ghost"
104→            size="icon"
105→            className="hover:bg-primary/10 h-8 w-8 rounded-full"
106→          >
107→            <svg
108→              width="20"
109→              height="20"
110→              viewBox="0 0 20 20"
111→              fill="none"
112→              xmlns="http://www.w3.org/2000/svg"
113→            >
114→              <path
115→                d="M15 5L5 15M5 5l10 10"
116→                stroke="currentColor"
117→                strokeWidth="2"
118→                strokeLinecap="round"
119→              />
120→            </svg>
121→          </Button>
122→        </div>
123→      </div>
124→
125→      {/* Content */}
126→      <div className="flex-1 overflow-y-auto p-4">
127→        {loading ? (
128→          <div className="flex h-full items-center justify-center">
129→            <div className="text-muted-foreground">{t('loading')}</div>
130→          </div>
131→        ) : messages.length === 0 ? (
132→          <div className="flex h-full flex-col items-center justify-center gap-2">
133→            <svg
134→              width="48"
135→              height="48"
136→              viewBox="0 0 24 24"
137→              fill="none"
138→              xmlns="http://www.w3.org/2000/svg"
139→              className="text-muted-foreground"
140→            >
141→              <path
142→                d="M12 17.27L18.18 21l-1.64-7.03L22 9.24l-7.19-.61L12 2 9.19 8.63 2 9.24l5.46 4.73L5.82 21z"
143→                fill="currentColor"
144→                opacity="0.3"
145→              />
146→            </svg>
147→            <p className="text-muted-foreground text-sm">{t('noStarredMessages')}</p>
148→          </div>
149→        ) : (
150→          <div className="space-y-2">
151→            {messages.map((message) => (
152→              <Card
153→                key={`${message.conversationId}-${message.turnId}`}
154→                className="group relative cursor-pointer p-3 transition-all hover:shadow-md"
155→                onClick={() => handleMessageClick(message)}
156→              >
157→                {/* Delete button */}
158→                <button
159→                  onClick={(e) => handleDeleteMessage(message, e)}
160→                  className="hover:bg-destructive/10 absolute top-2 right-2 rounded-full p-1 opacity-0 transition-opacity group-hover:opacity-100"
161→                  title={t('removeFromStarred')}
162→                >
163→                  <svg
164→                    width="16"
165→                    height="16"
166→                    viewBox="0 0 16 16"
167→                    fill="none"
168→                    xmlns="http://www.w3.org/2000/svg"
169→                    className="text-destructive"
170→                  >
171→                    <path
172→                      d="M4 4l8 8M12 4l-8 8"
173→                      stroke="currentColor"
174→                      strokeWidth="2"
175→                      strokeLinecap="round"
176→                    />
177→                  </svg>
178→                </button>
179→
180→                {/* Message content */}
181→                <div className="pr-6">
182→                  <div className="mb-1 flex items-start gap-2">
183→                    <svg
184→                      width="16"
185→                      height="16"
186→                      viewBox="0 0 24 24"
187→                      fill="none"
188→                      xmlns="http://www.w3.org/2000/svg"
189→                      className="text-primary mt-0.5 shrink-0"
190→                    >
191→                      <path
192→                        d="M12 17.27L18.18 21l-1.64-7.03L22 9.24l-7.19-.61L12 2 9.19 8.63 2 9.24l5.46 4.73L5.82 21z"
193→                        fill="currentColor"
194→                      />
195→                    </svg>
196→                    <p className="line-clamp-2 text-sm font-medium">
197→                      {truncateText(message.content, 100)}
198→                    </p>
199→                  </div>
200→
201→                  {/* Conversation info */}
202→                  <div className="ml-6 space-y-1">
203→                    {message.conversationTitle && (
204→                      <p className="text-muted-foreground truncate text-xs">
205→                        {message.conversationTitle}
206→                      </p>
207→                    )}
208→                    <p className="text-muted-foreground text-xs">{formatDate(message.starredAt)}</p>
209→                  </div>
210→                </div>
211→              </Card>
212→            ))}
213→          </div>
214→        )}
215→      </div>
216→    </div>
