 12→function hashString(input: string): string {
 13→  let h = 2166136261 >>> 0;
 14→  for (let i = 0; i < input.length; i++) {
 15→    h ^= input.charCodeAt(i);
 16→    h = Math.imul(h, 16777619);
 17→  }
 18→  return (h >>> 0).toString(36);
 19→}
