165→const MANIFEST_DEFAULT_DOMAINS = new Set(
166→  [
167→    ...(chrome.runtime.getManifest().host_permissions || []),
168→    ...(chrome.runtime.getManifest().content_scripts?.flatMap((c) => c.matches || []) || []),
169→  ]
170→    .map(patternToDomain)
171→    .filter((d): d is string => !!d),
172→);
173→
174→function patternToDomain(pattern: string | undefined): string | null {
175→  if (!pattern) return null;
176→  try {
177→    const withoutScheme = pattern.replace(/^[^:]+:\/\//, '');
178→    const hostPart = withoutScheme.replace(/\/.*$/, '').replace(/^\*\./, '');
179→    return hostPart || null;
180→  } catch {
181→    return null;
182→  }
183→}
184→
185→function toMatchPatterns(domain: string): string[] {
186→  const normalized = domain
187→    .trim()
188→    .toLowerCase()
189→    .replace(/^https?:\/\//, '')
190→    .replace(/^www\./, '')
191→    .replace(/\/.*$/, '')
192→    .replace(/^\*\./, '');
193→
194→  if (!normalized) return [];
195→  return [`https://*.${normalized}/*`, `http://*.${normalized}/*`];
196→}
197→
198→function extractDomainsFromOrigins(origins?: string[]): string[] {
199→  if (!Array.isArray(origins)) return [];
200→  const domains = origins
201→    .map(patternToDomain)
202→    .filter((d): d is string => !!d)
203→    .filter((d) => !MANIFEST_DEFAULT_DOMAINS.has(d));
204→  return Array.from(new Set(domains));
205→}
206→
207→async function filterGrantedOrigins(patterns: string[]): Promise<string[]> {
208→  const granted: string[] = [];
209→
210→  for (const origin of patterns) {
211→    try {
212→      const hasPermission = await browser.permissions.contains({ origins: [origin] });
213→      if (hasPermission) {
214→        granted.push(origin);
215→      }
216→    } catch (error) {
217→      console.warn('[Background] Failed to check permission for', origin, error);
218→    }
219→  }
220→
221→  return granted;
222→}
