224→async function syncCustomContentScripts(domains?: string[]): Promise<void> {
225→  if (!chrome.scripting?.registerContentScripts) return;
226→
227→  const manifestContentScript = chrome.runtime.getManifest().content_scripts?.[0];
228→  if (!manifestContentScript) return;
229→
230→  const domainList =
231→    domains ??
232→    (
233→      await chrome.storage.sync.get({
234→        [CUSTOM_WEBSITE_KEY]: [],
235→      })
236→    )[CUSTOM_WEBSITE_KEY];
237→
238→  const matchPatterns = Array.from(
239→    new Set((Array.isArray(domainList) ? domainList : []).flatMap(toMatchPatterns).filter(Boolean)),
240→  );
241→
242→  const grantedMatches = await filterGrantedOrigins(matchPatterns);
243→
244→  try {
245→    await chrome.scripting.unregisterContentScripts({ ids: [CUSTOM_CONTENT_SCRIPT_ID] });
246→  } catch {
247→    // No-op if script was not registered
248→  }
249→
250→  if (!grantedMatches.length) return;
251→
252→  const runAt =
253→    manifestContentScript.run_at === 'document_start'
254→      ? 'document_start'
255→      : manifestContentScript.run_at === 'document_end'
256→        ? 'document_end'
257→        : 'document_idle';
258→
259→  try {
260→    await chrome.scripting.registerContentScripts([
261→      {
262→        id: CUSTOM_CONTENT_SCRIPT_ID,
263→        js: manifestContentScript.js || [],
264→        css: manifestContentScript.css,
265→        matches: grantedMatches,
266→        allFrames: manifestContentScript.all_frames,
267→        runAt,
268→        persistAcrossSessions: true,
269→      },
270→    ]);
271→    console.log('[Background] Custom content scripts registered for', grantedMatches);
272→  } catch (error) {
273→    console.error('[Background] Failed to register custom content scripts:', error);
274→  }
275→}
