355→    return this.serialize(async () => {
356→      const data = await this.getFromStorage();
357→
358→      if (!data.messages[message.conversationId]) {
359→        data.messages[message.conversationId] = [];
360→      }
361→
362→      // Check if message already exists
363→      const exists = data.messages[message.conversationId].some((m) => m.turnId === message.turnId);
364→
365→      if (!exists) {
366→        // Truncate content to save storage space
367→        // Popup is ~360px wide with line-clamp-2, showing ~50-60 chars max
368→        const MAX_CONTENT_LENGTH = 60;
369→        const truncatedMessage: StarredMessage = {
370→          ...message,
371→          content:
372→            message.content.length > MAX_CONTENT_LENGTH
373→              ? message.content.slice(0, MAX_CONTENT_LENGTH) + '...'
374→              : message.content,
375→        };
376→        data.messages[message.conversationId].push(truncatedMessage);
