575→      // Handle starred messages operations
576→      if (message && message.type && message.type.startsWith('gv.starred.')) {
577→        switch (message.type) {
578→          case 'gv.starred.add': {
579→            const added = await starredMessagesManager.addStarredMessage(message.payload);
580→            sendResponse({ ok: true, added });
581→            return;
582→          }
583→          case 'gv.starred.remove': {
