640→          }
641→          case 'gv.fork.getGroup': {
642→            const nodes = await forkNodesManager.getGroup(message.payload.forkGroupId);
643→            sendResponse({ ok: true, nodes });
644→            return;
645→          }
646→        }
647→      }
648→
649→      // Handle sync operations
650→      if (message && message.type && message.type.startsWith('gv.sync.')) {
651→        switch (message.type) {
652→          case 'gv.sync.authenticate': {
653→            const interactive = message.payload?.interactive !== false;
654→            const success = await googleDriveSyncService.authenticate(interactive);
655→            sendResponse({ ok: success, state: await googleDriveSyncService.getState() });
656→            return;
657→          }
658→          case 'gv.sync.signOut': {
659→            await googleDriveSyncService.signOut();
660→            sendResponse({ ok: true, state: await googleDriveSyncService.getState() });
661→            return;
662→          }
663→          case 'gv.sync.upload': {
664→            const {
665→              folders,
666→              prompts,
667→              interactive,
668→              platform: rawPlatform,
669→              accountScope: rawScope,
670→            } = message.payload as {
671→              folders: FolderData;
672→              prompts: PromptItem[];
673→              interactive?: boolean;
674→              platform?: 'gemini' | 'aistudio';
675→              accountScope?: unknown;
676→            };
677→            const platform = rawPlatform || 'gemini';
678→            const accountScope = await resolveAccountScopeForMessage(
679→              sender,
680→              platform,
681→              isSyncAccountScope(rawScope) ? rawScope : undefined,
682→            );
683→            // Also get starred messages and fork nodes from local storage (only for Gemini platform)
684→            const starredDataRaw =
685→              platform !== 'aistudio' ? await starredMessagesManager.getAllStarredMessages() : null;
686→            const forksDataRaw =
687→              platform !== 'aistudio' ? await forkNodesManager.getAllForkNodes() : null;
688→            const starredData =
689→              starredDataRaw && accountScope
690→                ? filterStarredByRouteScope(starredDataRaw, accountScope.routeUserId)
691→                : starredDataRaw;
692→            const forksData =
693→              forksDataRaw && accountScope
694→                ? filterForkNodesByRouteScope(forksDataRaw, accountScope.routeUserId)
695→                : forksDataRaw;
696→            const success = await googleDriveSyncService.upload(
697→              folders,
698→              prompts,
699→              starredData,
700→              interactive !== false,
701→              platform,
702→              forksData,
703→              accountScope,
704→            );
705→            sendResponse({ ok: success, state: await googleDriveSyncService.getState() });
706→            return;
707→          }
708→          case 'gv.sync.download': {
709→            const interactive = message.payload?.interactive !== false;
710→            const platform = (message.payload?.platform as 'gemini' | 'aistudio') || 'gemini';
711→            const rawScope = message.payload?.accountScope;
712→            const accountScope = await resolveAccountScopeForMessage(
713→              sender,
714→              platform,
715→              isSyncAccountScope(rawScope) ? rawScope : undefined,
716→            );
717→            const data = await googleDriveSyncService.download(interactive, platform, accountScope);
718→            // NOTE: We intentionally do NOT save to storage here.
719→            // The caller (Popup) is responsible for merging with local data and saving.
720→            // This prevents data loss from overwriting local changes.
721→            console.log(
722→              `[Background] Downloaded data for ${platform}, returning to caller for merge`,
723→            );
724→            sendResponse({
725→              ok: true,
726→              data,
727→              state: await googleDriveSyncService.getState(),
728→            });
729→            return;
730→          }
731→          case 'gv.sync.getState': {
732→            sendResponse({ ok: true, state: await googleDriveSyncService.getState() });
733→            return;
734→          }
735→          case 'gv.sync.setMode': {
736→            const mode = message.payload?.mode as SyncMode;
737→            if (mode) {
738→              await googleDriveSyncService.setMode(mode);
739→            }
740→            sendResponse({ ok: true, state: await googleDriveSyncService.getState() });
741→            return;
742→          }
743→        }
744→      }
745→
746→      // Handle popup opening request
747→      if (message && message.type === 'gv.openPopup') {
748→        try {
749→          await chrome.action.openPopup();
750→          sendResponse({ ok: true });
751→        } catch (e) {
752→          // Fallback: If openPopup fails, user can click the extension icon
753→          console.warn('[GV] Failed to open popup programmatically:', e);
754→          sendResponse({ ok: false, error: e instanceof Error ? e.message : String(e) });
755→        }
756→        return;
757→      }
758→
759→      // Handle sync to IDE (bypasses page CSP)
760→      if (message?.type === 'gv.syncToIDE') {
761→        const url = String(message.url || '');
762→        const data = message.data || [];
763→        try {
764→          const response = await fetch(url, {
765→            method: 'POST',
766→            headers: { 'Content-Type': 'application/json' },
767→            mode: 'cors',
768→            body: JSON.stringify(data),
769→          });
770→
771→          if (!response.ok) {
772→            sendResponse({ ok: false, error: `HTTP ${response.status}` });
773→          } else {
774→            const result = await response.json();
775→            sendResponse({ ok: true, data: result });
776→          }
777→        } catch (e) {
778→          sendResponse({ ok: false, error: e instanceof Error ? e.message : String(e) });
779→        }
780→        return;
781→      }
782→
783→      // Handle check sync server status (bypasses page CSP)
784→      if (message?.type === 'gv.checkSyncStatus') {
785→        const url = String(message.url || '');
786→        const timeout = Number(message.timeout || 200);
787→        const controller = new AbortController();
788→        const timeoutId = setTimeout(() => controller.abort(), timeout);
789→
790→        try {
791→          const response = await fetch(url, {
792→            method: 'GET',
793→            signal: controller.signal,
794→          });
795→          sendResponse({ ok: response.ok });
796→        } catch {
797→          sendResponse({ ok: false });
798→        } finally {
799→          clearTimeout(timeoutId);
800→        }
801→        return;
802→      }
803→
804→      // Handle image fetch via page context (for Firefox/Safari cookie partitioning)
805→      // Uses chrome.scripting.executeScript in MAIN world so the page's own fetch is used,
806→      // which has access to the correct Google authentication cookies.
807→      if (message?.type === 'gv.fetchImageViaPage') {
808→        const url = String(message.url || '');
809→        const tabId = sender?.tab?.id;
810→        if (!tabId || !/^https?:\/\//i.test(url)) {
811→          sendResponse({ ok: false, error: 'invalid' });
812→          return;
813→        }
814→        if (!chrome.scripting?.executeScript) {
815→          sendResponse({ ok: false, error: 'scripting_api_unavailable' });
816→          return;
817→        }
818→        try {
819→          const results = await chrome.scripting.executeScript({
820→            target: { tabId },
821→            world: 'MAIN' as chrome.scripting.ExecutionWorld,
822→            func: async (imageUrl: string) => {
823→              const safeFetch = async (credentials: RequestCredentials) => {
824→                try {
825→                  console.log(`[PageContext] Fetching with ${credentials}:`, imageUrl);
826→                  const resp = await fetch(imageUrl, { credentials });
827→                  if (resp.ok) return await resp.blob();
828→                  console.warn(`[PageContext] Fetch (${credentials}) HTTP error:`, resp.status);
829→                } catch (e) {
830→                  console.warn(`[PageContext] Fetch (${credentials}) error:`, e);
831→                }
832→                return null;
833→              };
834→
835→              try {
836→                // Try with credentials first, then without (fix for Firefox CSP/CORS)
837→                const blob = (await safeFetch('include')) || (await safeFetch('omit'));
838→                if (!blob) {
839→                  console.error('[PageContext] All fetch attempts failed');
840→                  return null;
841→                }
842→
843→                return new Promise<{
844→                  contentType: string;
845→                  base64: string;
846→                } | null>((resolve) => {
847→                  const reader = new FileReader();
848→                  reader.onload = () => {
849→                    const dataUrl = String(reader.result || '');
850→                    const commaIdx = dataUrl.indexOf(',');
851→                    if (commaIdx < 0) {
852→                      resolve(null);
853→                      return;
854→                    }
855→                    resolve({
856→                      contentType: blob.type || 'application/octet-stream',
857→                      base64: dataUrl.substring(commaIdx + 1),
858→                    });
859→                  };
860→                  reader.onerror = () => resolve(null);
861→                  reader.readAsDataURL(blob);
862→                });
863→              } catch {
864→                return null;
865→              }
866→            },
867→            args: [url],
868→          });
869→          const result = results?.[0]?.result as {
870→            contentType: string;
871→            base64: string;
872→          } | null;
873→          if (result?.base64) {
874→            sendResponse({
875→              ok: true,
876→              contentType: result.contentType,
877→              base64: result.base64,
878→              data: `data:${result.contentType};base64,${result.base64}`,
879→            });
880→          } else {
881→            sendResponse({ ok: false, error: 'page_fetch_failed' });
882→          }
883→        } catch (e: unknown) {
884→          const errMsg = e instanceof Error ? e.message : String(e);
885→          sendResponse({ ok: false, error: errMsg });
886→        }
887→        return;
888→      }
889→
890→      // Handle image fetch
891→      if (!message || message.type !== 'gv.fetchImage') return;
892→      const url = String(message.url || '');
893→      if (!/^https?:\/\//i.test(url)) {
894→        sendResponse({ ok: false, error: 'invalid_url' });
895→        return;
896→      }
897→
898→      const fetchWithFallback = async (fetchUrl: string) => {
899→        try {
900→          const r1 = await fetch(fetchUrl, { credentials: 'include', redirect: 'follow' });
901→          if (r1.ok) return r1;
902→        } catch {
903→          /* ignore include error */
904→        }
905→
906→        try {
907→          const r2 = await fetch(fetchUrl, { credentials: 'omit', redirect: 'follow' });
908→          return r2;
909→        } catch (e) {
910→          throw e;
911→        }
912→      };
913→
914→      fetchWithFallback(url)
915→        .then((response) => {
916→          if (!response.ok) throw new Error(`HTTP ${response.status}`);
917→          return response.blob();
918→        })
919→        .then((blob) => {
920→          return blob.arrayBuffer().then((ab) => {
921→            const b64 = arrayBufferToBase64(ab);
922→            const contentType = blob.type || 'image/png';
923→            const dataUrl = `data:${contentType};base64,${b64}`;
924→            sendResponse({
925→              ok: true,
926→              data: dataUrl,
927→              contentType,
928→              base64: b64,
929→            });
930→          });
931→        })
932→        .catch((err) => {
933→          console.error('[Background] gv.fetchImage Final failure:', err);
934→          sendResponse({ ok: false, error: err.message });
935→        });
936→      return;
937→    } catch (e) {
938→      try {
939→        sendResponse({ ok: false, error: e instanceof Error ? e.message : String(e) });
940→      } catch {}
941→    }
942→  })();
943→  return true; // keep channel open for async sendResponse
944→});
945→
946→function arrayBufferToBase64(buffer: ArrayBuffer): string {
947→  let binary = '';
948→  const bytes = new Uint8Array(buffer);
949→  const len = bytes.byteLength;
950→  for (let i = 0; i < len; i++) {
951→    binary += String.fromCharCode(bytes[i]);
952→  }
953→  // btoa on service worker context is available
954→  return btoa(binary);
955→}
