  6→/**
  7→ * Merges two lists of items based on ID and updatedAt timestamp.
  8→ * Prefers the item with the later updatedAt timestamp.
  9→ */
 10→function mergeItems<T extends { id: string; updatedAt?: number; createdAt?: number }>(
 11→  localItems: T[],
 12→  cloudItems: T[],
 13→): T[] {
 14→  const itemMap = new Map<string, T>();
 15→
 16→  // Add all local items first
 17→  localItems.forEach((item) => {
 18→    itemMap.set(item.id, item);
 19→  });
 20→
 21→  // Merge cloud items
 22→  cloudItems.forEach((cloudItem) => {
 23→    const localItem = itemMap.get(cloudItem.id);
 24→    if (!localItem) {
 25→      // New item from cloud
 26→      itemMap.set(cloudItem.id, cloudItem);
 27→    } else {
 28→      // Conflict: compare timestamps
 29→      // Use createdAt as fallback for updatedAt
 30→      const cloudTime = cloudItem.updatedAt || cloudItem.createdAt || 0;
 31→      const localTime = localItem.updatedAt || localItem.createdAt || 0;
 32→
 33→      if (cloudTime > localTime) {
 34→        itemMap.set(cloudItem.id, cloudItem);
 35→      }
 36→      // If local is newer or equal, keep local
 37→    }
 38→  });
 39→
 40→  return Array.from(itemMap.values());
 41→}
