 43→/**
 44→ * Merges local and cloud folder data.
 45→ */
 46→export function mergeFolderData(local: FolderData, cloud: FolderData): FolderData {
 47→  // 1. Merge Folders list
 48→  const mergedFolders = mergeItems(local.folders, cloud.folders);
 49→
 50→  // 2. Merge Folder Contents
 51→  const mergedContents: Record<string, ConversationReference[]> = { ...local.folderContents };
 52→
 53→  // Iterate over cloud folders to ensure we capture all content
 54→  // (Even for folders we might have just added)
 55→  const allFolderIds = new Set([
 56→    ...Object.keys(local.folderContents),
 57→    ...Object.keys(cloud.folderContents),
 58→  ]);
 59→
 60→  allFolderIds.forEach((folderId) => {
 61→    const localConvos = local.folderContents[folderId] || [];
 62→    const cloudConvos = cloud.folderContents[folderId] || [];
 63→
 64→    // Merge conversation references: Cloud-first strategy
 65→    // This ensures renamed titles from cloud sync are applied to local
 66→    // - If user renamed title locally and uploaded, cloud has the new title
 67→    // - If user downloads on another device, cloud title should override local
 68→    // - If conversation only exists locally, keep it (new local addition)
 69→
 70→    const convoMap = new Map<string, ConversationReference>();
 71→
 72→    // Add local conversations first
 73→    localConvos.forEach((c) => convoMap.set(c.conversationId, c));
 74→
 75→    // Cloud conversations override local (this is the key change)
 76→    cloudConvos.forEach((c) => {
 77→      const existing = convoMap.get(c.conversationId);
 78→      if (!existing) {
 79→        // New from cloud
 80→        convoMap.set(c.conversationId, c);
 81→      } else {
 82→        // Merge: cloud properties override, but keep local-only properties
 83→        convoMap.set(c.conversationId, {
 84→          ...existing, // Keep any local-only properties
 85→          ...c, // Cloud overrides (title, customTitle, etc.)
 86→          // Preserve starred if set locally but not in cloud
 87→          starred: c.starred ?? existing.starred,
 88→        });
 89→      }
 90→    });
 91→
 92→    mergedContents[folderId] = Array.from(convoMap.values());
 93→  });
 94→
 95→  return {
 96→    folders: mergedFolders,
 97→    folderContents: mergedContents,
 98→  };
 99→}
