108→/**
109→ * Merges local and cloud starred messages.
110→ * Uses turnId as the unique key within each conversation.
111→ * Prefers the message with the newer starredAt timestamp when duplicates exist.
112→ */
113→export function mergeStarredMessages(
114→  local: StarredMessagesData,
115→  cloud: StarredMessagesData,
116→): StarredMessagesData {
117→  // Ensure we have valid input structures
118→  const localMessages = local?.messages || {};
119→  const cloudMessages = cloud?.messages || {};
120→
121→  // Get all conversation IDs from both sources
122→  const allConversationIds = new Set([
123→    ...Object.keys(localMessages),
124→    ...Object.keys(cloudMessages),
125→  ]);
126→
127→  const mergedMessages: Record<string, StarredMessage[]> = {};
128→
129→  allConversationIds.forEach((conversationId) => {
130→    const localConvoMessages = localMessages[conversationId] || [];
131→    const cloudConvoMessages = cloudMessages[conversationId] || [];
132→
133→    // Use Map with turnId as key for deduplication
134→    const messageMap = new Map<string, StarredMessage>();
135→
136→    // Add cloud messages first (so local can overwrite if newer)
137→    cloudConvoMessages.forEach((msg) => {
138→      messageMap.set(msg.turnId, msg);
139→    });
140→
141→    // Merge local messages - prefer newer starredAt
142→    localConvoMessages.forEach((localMsg) => {
143→      const existingMsg = messageMap.get(localMsg.turnId);
144→      if (!existingMsg) {
145→        // New message from local
146→        messageMap.set(localMsg.turnId, localMsg);
147→      } else {
148→        // Conflict: compare starredAt timestamps
149→        if (localMsg.starredAt >= existingMsg.starredAt) {
150→          messageMap.set(localMsg.turnId, localMsg);
151→        }
152→        // If cloud is newer, keep cloud (already in map)
153→      }
154→    });
155→
156→    // Only add non-empty arrays
157→    const mergedArray = Array.from(messageMap.values());
158→    if (mergedArray.length > 0) {
159→      mergedMessages[conversationId] = mergedArray;
160→    }
161→  });
162→
163→  return { messages: mergedMessages };
164→}
