166→/**
167→ * Merges local and cloud fork nodes.
168→ * Uses forkGroupId + turnId as the unique key within each conversation.
169→ * Prefers the node with the newer createdAt timestamp when duplicates exist.
170→ */
171→export function mergeForkNodes(local: ForkNodesData, cloud: ForkNodesData): ForkNodesData {
172→  const localNodes = local?.nodes || {};
173→  const cloudNodes = cloud?.nodes || {};
174→
175→  const allConversationIds = new Set([...Object.keys(localNodes), ...Object.keys(cloudNodes)]);
176→
177→  const mergedNodes: Record<string, ForkNode[]> = {};
178→
179→  allConversationIds.forEach((conversationId) => {
180→    const localConvoNodes = localNodes[conversationId] || [];
181→    const cloudConvoNodes = cloudNodes[conversationId] || [];
182→
183→    // Use "forkGroupId:turnId" as unique key
184→    const nodeMap = new Map<string, ForkNode>();
185→
186→    // Add cloud nodes first
187→    cloudConvoNodes.forEach((node) => {
188→      const key = `${node.forkGroupId}:${node.turnId}`;
189→      nodeMap.set(key, node);
190→    });
191→
192→    // Merge local nodes - prefer newer createdAt
193→    localConvoNodes.forEach((localNode) => {
194→      const key = `${localNode.forkGroupId}:${localNode.turnId}`;
195→      const existing = nodeMap.get(key);
196→      if (!existing) {
197→        nodeMap.set(key, localNode);
198→      } else if (localNode.createdAt >= existing.createdAt) {
199→        nodeMap.set(key, localNode);
200→      }
201→    });
202→
203→    const mergedArray = Array.from(nodeMap.values());
204→    if (mergedArray.length > 0) {
205→      mergedNodes[conversationId] = mergedArray;
206→    }
207→  });
208→
209→  // Rebuild groups index from merged nodes
210→  const mergedGroups: Record<string, string[]> = {};
211→  for (const [conversationId, nodes] of Object.entries(mergedNodes)) {
212→    for (const node of nodes) {
213→      if (!mergedGroups[node.forkGroupId]) {
214→        mergedGroups[node.forkGroupId] = [];
215→      }
216→      const groupKey = `${conversationId}:${node.turnId}`;
217→      if (!mergedGroups[node.forkGroupId].includes(groupKey)) {
218→        mergedGroups[node.forkGroupId].push(groupKey);
219→      }
220→    }
221→  }
222→
223→  return { nodes: mergedNodes, groups: mergedGroups };
224→}
