252→  private positionToggle(): void {
253→    if (!this.toggleBtn) return;
254→    const barRect = this.anchorElement.getBoundingClientRect();
255→    const btnSize = 24;
256→    const gap = 4;
257→    const minLeft = 8;
258→    const maxLeft = Math.max(minLeft, window.innerWidth - btnSize - 8);
259→    const leftPx = Math.max(minLeft, Math.min(Math.round(barRect.left - btnSize - gap), maxLeft));
260→    this.toggleBtn.style.left = `${leftPx}px`;
261→    this.toggleBtn.style.top = `${Math.round(barRect.top + barRect.height / 2 - btnSize / 2)}px`;
262→  }
263→
264→  private positionPanel(): void {
265→    if (!this.panelEl) return;
266→    const barRect = this.anchorElement.getBoundingClientRect();
267→    const panelWidth = 320;
268→    const gap = 12;
269→    const maxHeight = Math.min(500, window.innerHeight * 0.7);
270→    const barCenterY = barRect.top + barRect.height / 2;
271→    const isRTL = this.isRTLContext();
272→
273→    let left: number;
274→    if (isRTL) {
275→      // In RTL, bar is on the left — place panel to its right
276→      left = barRect.right + gap;
277→      if (left + panelWidth > window.innerWidth - 8) {
278→        left = window.innerWidth - panelWidth - 8;
279→      }
280→    } else {
281→      // In LTR, bar is on the right — place panel to its left
282→      left = barRect.left - panelWidth - gap;
283→      if (left < 8) left = 8;
284→    }
285→
286→    this.panelEl.style.maxHeight = `${Math.round(maxHeight)}px`;
287→    this.panelEl.style.left = `${Math.round(left)}px`;
288→
289→    // Measure actual rendered height to center properly (works for both few and many items)
290→    const panelHeight = this.panelEl.offsetHeight || maxHeight;
291→    let top = barCenterY - panelHeight / 2;
292→    top = Math.max(8, Math.min(top, window.innerHeight - panelHeight - 8));
293→
294→    this.panelEl.style.top = `${Math.round(top)}px`;
295→  }
296→
297→  private applyFilter(): void {
298→    if (!this.searchQuery) {
299→      this.filteredMarkers = this.markers;
300→    } else {
301→      const q = this.searchQuery.toLowerCase();
302→      this.filteredMarkers = this.markers.filter((m) => m.summary.toLowerCase().includes(q));
303→    }
304→    if (this._isOpen) {
305→      this.renderList();
306→    }
307→    this.onSearchChange?.(this.searchQuery);
308→  }
309→
310→  private handleSearchInput(): void {
311→    if (this.searchDebounceTimer) {
312→      clearTimeout(this.searchDebounceTimer);
313→    }
314→    this.searchDebounceTimer = window.setTimeout(() => {
315→      this.searchDebounceTimer = null;
316→      this.searchQuery = this.searchInput?.value.trim() ?? '';
317→      this.applyFilter();
318→    }, SEARCH_DEBOUNCE_MS);
319→  }
320→
321→  private renderList(): void {
322→    if (!this.listEl) return;
323→    this.listEl.textContent = '';
324→
325→    if (this.filteredMarkers.length === 0) {
326→      const empty = document.createElement('div');
327→      empty.className = 'timeline-preview-empty';
328→      empty.textContent = this.searchQuery
329→        ? getTranslationSync('timelinePreviewNoResults')
330→        : getTranslationSync('timelinePreviewNoMessages');
331→      this.listEl.appendChild(empty);
332→      return;
333→    }
334→
335→    const fragment = document.createDocumentFragment();
336→    for (const marker of this.filteredMarkers) {
337→      fragment.appendChild(this.createItem(marker));
338→    }
339→    this.listEl.appendChild(fragment);
340→  }
341→
342→  private createItem(marker: PreviewMarkerData): HTMLElement {
343→    const item = document.createElement('div');
344→    item.className = 'timeline-preview-item';
345→    item.dataset.turnId = marker.id;
346→
347→    if (marker.starred) {
348→      item.classList.add('starred');
349→    }
350→    if (marker.id === this.activeTurnId) {
351→      item.classList.add('active');
352→    }
353→
354→    const indexLabel = document.createElement('span');
355→    indexLabel.className = 'timeline-preview-index';
356→    indexLabel.textContent = `${marker.index + 1}`;
357→    item.appendChild(indexLabel);
358→
359→    const text = document.createElement('span');
360→    text.className = 'timeline-preview-text';
361→    text.setAttribute('dir', 'auto');
362→    const displayText = this.truncateText(marker.summary, 80);
363→    if (this.searchQuery) {
364→      this.appendHighlighted(text, displayText, this.searchQuery);
365→    } else {
366→      text.textContent = displayText;
367→    }
368→    item.appendChild(text);
369→
370→    item.addEventListener('click', () => {
371→      this.onNavigate?.(marker.id, marker.index);
372→    });
373→
374→    return item;
375→  }
376→
377→  /** Split text around case-insensitive query matches and wrap each match in <mark>. */
378→  private appendHighlighted(container: HTMLElement, text: string, query: string): void {
379→    const lowerText = text.toLowerCase();
380→    const lowerQuery = query.toLowerCase();
381→    let cursor = 0;
382→    let idx = lowerText.indexOf(lowerQuery, cursor);
383→    while (idx !== -1) {
384→      if (idx > cursor) {
385→        container.appendChild(document.createTextNode(text.slice(cursor, idx)));
386→      }
387→      const mark = document.createElement('mark');
388→      mark.className = 'timeline-preview-highlight';
389→      mark.textContent = text.slice(idx, idx + query.length);
390→      container.appendChild(mark);
391→      cursor = idx + query.length;
392→      idx = lowerText.indexOf(lowerQuery, cursor);
393→    }
394→    if (cursor < text.length) {
395→      container.appendChild(document.createTextNode(text.slice(cursor)));
396→    }
397→  }
398→
399→  private truncateText(text: string, maxLen: number): string {
400→    if (text.length <= maxLen) return text;
401→    return text.slice(0, maxLen - 1) + '\u2026';
402→  }
403→
404→  private updateActiveHighlight(): void {
405→    if (!this.listEl) return;
406→    const items = this.listEl.querySelectorAll('.timeline-preview-item');
407→    items.forEach((item) => {
408→      const el = item as HTMLElement;
409→      el.classList.toggle('active', el.dataset.turnId === this.activeTurnId);
410→    });
411→  }
412→
413→  private scrollActiveIntoView(): void {
414→    if (!this.listEl || !this.activeTurnId) return;
415→    const activeItem = this.listEl.querySelector(
416→      '.timeline-preview-item.active',
417→    ) as HTMLElement | null;
418→    activeItem?.scrollIntoView?.({ block: 'nearest', behavior: 'smooth' });
419→  }
420→
421→  private markersEqual(newMarkers: ReadonlyArray<PreviewMarkerData>): boolean {
422→    if (newMarkers.length !== this.markers.length) return false;
423→    for (let i = 0; i < newMarkers.length; i++) {
424→      const a = this.markers[i];
425→      const b = newMarkers[i];
426→      if (a.id !== b.id || a.summary !== b.summary || a.starred !== b.starred) return false;
427→    }
428→    return true;
429→  }
430→}
